const centralUUID = env.get('CENTRAL_UUID');
const devices = flow.get('devices') || {};

let output = {};

// Process each device ID in the input payload
for (let key in msg.payload) {
    const device = devices[key.trim()];
    const deviceId = device.uniqueId;
    // Remove hyphens from the device ID
    let cleanDeviceId = deviceId.replace(/-/g, '');
    
    // Calculate the sum of all pulses for this device
    let totalPulses = msg.payload[key].reduce((sum, entry) => {
        return sum + entry.values.pulses;
    }, 0);
    
    // Create the new format with current timestamp and total pulses
    output[cleanDeviceId] = {
        ts: new Date().getTime(),
        values: {
            pulses: totalPulses
        }
    };
}

// Set the transformed data as the new payload
msg.payload = output;

return msg;
